import { useState } from "react";

import InputForm from "../../Components/Input/InputForm";
import MainBtns from "../../Components/Buttons/MainBtns";

function PhotoPage() {
  const [image, setImage] = useState(null);

  const handleFileChange = (e) => {
    const file = e.target.files[0];
    if (file && file.type.startsWith("image/")) {
      const imageUrl = URL.createObjectURL(file);
      setImage(imageUrl);
    } else {
      setImage(null);
    }
  };


  return (
    <div style={{flex:1, display:"flex", flexDirection:"column", alignItems:"center"}}  
    >
      <header style={{display:"flex",flexDirection:"column", borderBottom:"1px solid #ccc", alignItems:"center", justifyContent:"center", width:"100%"}}>
        <h2 style={{fontWeight:"500"}}>Photo</h2>
        <span style={{marginBottom:"1rem", fontWeight:"100"}}>Add Photo</span>
      </header>
      <div style={{display:"flex", flexDirection:"column",justifyContent:"center", alignItems:"center", width:"100%", padding:"0 10%"}} className="photo-page-main">

        <div style={{marginTop:"10px",border:"1px solid rgba(37, 37, 37, 0.541)", padding:"10px", width:"100%"}}>
          <div style={{backgroundColor:"oklch(97.59% 0.0029 264.54deg)", padding:"10px", display:"flex", justifyContent:"center"}}>

            <div className="image-preview">
              {image ? (
                <img src={image} alt="preview" />
              ) : (
                <div style={{width:"200px", height:"200px"}}></div>
              )}
            </div>
          </div>
        </div>

        <div style={{width:"100%", display:"flex", flexDirection:"column"}}>
          <div style={{marginTop:"15px", marginBottom:"20px"}}>
            <InputForm zstyle={"void"} type={"file"} TextPlaceholder={"image"} accept={"image/*"} Id={"InputImage"} funct={handleFileChange} />
            <label htmlFor="InputImage" className="image-input">Загрузить картинку</label>
          </div>
          <div style={{display:"flex"}}>
            <MainBtns Style={"purple-btn"} Text={"Сохранить"}/>
          </div>
        </div>
      </div>

    </div>
  );
}

export default PhotoPage;
